
(function(){
  const STYLE_ID='g2-dashboard-consignes-shortcut-v1';
  function normalize(value){return String(value||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/\s+/g,' ').trim();}
  function isDashboard(){const route=location.hash.replace(/^#/,'')||sessionStorage.getItem('g2_route')||'/dashboard'; return route==='/dashboard'||route===''||route==='/';}
  function go(){sessionStorage.setItem('g2_route','/consignes'); location.hash='/consignes';}
  function ensureStyle(){
    if(document.getElementById(STYLE_ID)) return;
    const style=document.createElement('style');
    style.id=STYLE_ID;
    style.textContent='[data-g2-consignes-shortcut]{cursor:pointer!important;transition:transform .15s ease,box-shadow .15s ease}[data-g2-consignes-shortcut]:hover{transform:translateY(-2px);box-shadow:0 14px 34px rgba(0,26,141,.16)!important}[data-g2-consignes-shortcut]:focus{outline:3px solid rgba(255,107,0,.35);outline-offset:2px}';
    document.head.appendChild(style);
  }
  function findCard(){
    const title=[...document.querySelectorAll('h1,h2,h3,div')].find(el=>normalize(el.textContent)==='dernieres consignes'||normalize(el.textContent)==='dernières consignes');
    return title?.closest('section,article,[class*="rounded-xl"],[class*="shadow"],div');
  }
  function activate(){
    if(!isDashboard()) return;
    ensureStyle();
    const card=findCard();
    if(!card) return;
    card.dataset.g2ConsignesShortcut='1';
    card.dataset.g2DashboardRoute='/consignes';
    card.setAttribute('role','button');
    card.setAttribute('tabindex','0');
    card.title='Ouvrir les consignes';
  }
  document.addEventListener('click',event=>{
    if(!isDashboard()) return;
    if(event.target.closest('a,button,input,select,textarea,label')) return;
    const card=event.target.closest('[data-g2-consignes-shortcut]');
    if(card) go();
  },true);
  document.addEventListener('keydown',event=>{
    if(!isDashboard()) return;
    if(event.key!=='Enter'&&event.key!==' ') return;
    const card=event.target.closest&&event.target.closest('[data-g2-consignes-shortcut]');
    if(!card) return;
    event.preventDefault();
    go();
  },true);
  let scheduled=false;
  function schedule(){if(scheduled) return; scheduled=true; requestAnimationFrame(()=>{scheduled=false; activate();});}
  const observer=new MutationObserver(schedule);
  observer.observe(document.getElementById('root')||document.documentElement,{childList:true,subtree:true});
  window.addEventListener('hashchange',()=>setTimeout(activate,120));
  setTimeout(activate,220);
})();

(function(){
  const STYLE_ID='g2-dashboard-remove-leaves-v1';
  function normalize(value){return String(value||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/\s+/g,' ').trim();}
  function isDashboard(){const route=location.hash.replace(/^#/,'')||sessionStorage.getItem('g2_route')||'/dashboard'; return route==='/dashboard'||route===''||route==='/';}
  function ensureStyle(){
    if(document.getElementById(STYLE_ID)) return;
    const style=document.createElement('style');
    style.id=STYLE_ID;
    style.textContent='[data-g2-hide-dashboard-leaves]{display:none!important}';
    document.head.appendChild(style);
  }
  function hide(){
    ensureStyle();
    if(!isDashboard()) return;
    document.getElementById('g2-dashboard-leave-validation-panel')?.remove();
    document.querySelectorAll('[data-g2-hide-dashboard-leaves]').forEach(el=>el.removeAttribute('data-g2-hide-dashboard-leaves'));
    [...document.querySelectorAll('section,article,div,span,p')].forEach(el=>{
      const text=normalize(el.textContent);
      if(!text||text.length>220) return;
      if(!text.includes('conges')&&!text.includes('congés')&&!text.includes('validation des conges')&&!text.includes('validation des congés')) return;
      const card=el.closest('[class*="rounded-xl"],section,article')||el;
      if(card&&card.id!=='root') card.setAttribute('data-g2-hide-dashboard-leaves','1');
    });
  }
  let scheduled=false;
  function schedule(){if(scheduled) return; scheduled=true; requestAnimationFrame(()=>{scheduled=false; hide();});}
  const observer=new MutationObserver(schedule);
  observer.observe(document.getElementById('root')||document.documentElement,{childList:true,subtree:true});
  window.addEventListener('hashchange',()=>setTimeout(hide,120));
  setTimeout(hide,220);
})();

(function(){
  const routeKey = 'g2_route';
  if (location.protocol === 'file:' && !location.hash && !sessionStorage.getItem(routeKey)) {
    sessionStorage.setItem(routeKey, localStorage.getItem('g2_session') === 'true' ? '/dashboard' : '/login');
  }

  try {
    const agentsRaw = localStorage.getItem('g2_agents');
    const agents = agentsRaw ? JSON.parse(agentsRaw) : [];
    if (Array.isArray(agents)) {
      const requiredAgents = [
        {id:'11',grade:'GPX',nom:'BACHELIN',role:'',observation:'',email:'bachelin@g2.police.fr',telephone:'06 12 34 56 79',unite:'Brigade de Roulement Jour',actif:true},
        {id:'12',grade:'PA',nom:'AKROUM',role:'',observation:'',email:'akroum@g2.police.fr',telephone:'06 23 45 67 90',unite:'Brigade de Roulement Jour',actif:true}
      ];
      let changed = false;
      requiredAgents.forEach((requiredAgent) => {
        const index = agents.findIndex((agent) => String(agent.nom || '').toUpperCase() === requiredAgent.nom || String(agent.id || '') === requiredAgent.id);
        if (index >= 0) {
          agents[index] = {...agents[index], ...requiredAgent, actif:true};
        } else {
          agents.push(requiredAgent);
        }
        changed = true;
      });
      if (changed) localStorage.setItem('g2_agents', JSON.stringify(agents));
    }
  } catch (error) {}

  const sessionMaxMs = 30 * 60 * 1000;
  function clearSecureSession() {
    localStorage.removeItem('g2_session');
    localStorage.removeItem('g2_current_agent');
    localStorage.removeItem('g2_last_activity');
    sessionStorage.setItem('g2_route', '/login');
  }
  try {
    const now = Date.now();
    const last = Number(localStorage.getItem('g2_last_activity') || now);
    if (localStorage.getItem('g2_session') === 'true' && now - last > sessionMaxMs) {
      clearSecureSession();
      if (!location.hash.includes('login')) location.hash = '/login';
    } else if (localStorage.getItem('g2_session') === 'true') {
      localStorage.setItem('g2_last_activity', String(now));
    }
    ['click','keydown','mousemove','touchstart'].forEach((eventName) => {
      window.addEventListener(eventName, () => {
        if (localStorage.getItem('g2_session') === 'true') {
          localStorage.setItem('g2_last_activity', String(Date.now()));
        }
      }, {passive:true});
    });
  } catch (error) {}
  const normalizeType = (value) => {
    const raw = String(value || '').trim();
    const key = raw.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
    if (!raw || key === 'secourisme' || key === 'permis b') return null;
    if (key === 'cougar') return 'COUGAR';
    if (key === 'fusil a pompe') return 'FUSIL À POMPE';
    if (key === 'telesco' || key === 'telesco.' || key === 'baton telescopique' || key === 'baton telescopique') return 'BATON TELESCOPIQUE';
    if (key === 'tonfa') return 'TONFA';
    if (key === 'lbd') return 'LBD';
    if (key === 'pie') return 'PIE';
    if (key === 'hk') return 'HK';
    if (key === 'mp7') return 'MP7';
    if (key === 'genl') return 'GENL';
    return raw.toUpperCase();
  };
  try {
    const raw = localStorage.getItem('g2_habilitations');
    if (raw) {
      const cleaned = JSON.parse(raw).map((item) => ({...item, type: normalizeType(item && item.type)})).filter((item) => item.type);
      localStorage.setItem('g2_habilitations', JSON.stringify(cleaned));
    }
  } catch (error) {}
  const keys = new Set(['g2_agents','g2_leaves','g2_tirs','g2_habilitations','g2_consignes','g2_weekly']);
  const channel = 'BroadcastChannel' in window ? new BroadcastChannel('g2-connect-sync') : null;
  let timer = null;
  function refreshSoon(){ clearTimeout(timer); timer = setTimeout(() => location.reload(), 450); }
  function notify(key){ if (!keys.has(key)) return; try { channel && channel.postMessage({key, time: Date.now()}); } catch (error) {} }
  const originalSet = localStorage.setItem;
  const originalRemove = localStorage.removeItem;
  localStorage.setItem = function(key, value){ originalSet.apply(this, arguments); notify(key); };
  localStorage.removeItem = function(key){ originalRemove.apply(this, arguments); notify(key); };
  window.addEventListener('storage', (event) => { if (keys.has(event.key)) refreshSoon(); });
  if (channel) channel.onmessage = (event) => { if (event.data && keys.has(event.data.key)) refreshSoon(); };
})();

(function(){
  const BACKUP_KEY = 'g2_autosave_bundle_v2';
  const DATA_KEYS = ['g2_agents','g2_leaves','g2_tirs','g2_habilitations','g2_consignes','g2_weekly'];
  function meaningful(value){
    if (value == null || value === '') return false;
    if (value === '[]' || value === '{}') return false;
    return true;
  }
  function readBackup(){
    try { return JSON.parse(localStorage.getItem(BACKUP_KEY) || '{}'); } catch (error) { return {}; }
  }
  function writeBackup(){
    try {
      const data = {};
      DATA_KEYS.forEach((key) => { data[key] = localStorage.getItem(key); });
      localStorage.setItem(BACKUP_KEY, JSON.stringify({date:new Date().toISOString(), data}));
    } catch (error) {}
  }
  function restoreMissingData(){
    const backup = readBackup();
    const data = backup && backup.data ? backup.data : {};
    let restored = false;
    DATA_KEYS.forEach((key) => {
      const current = localStorage.getItem(key);
      const saved = data[key];
      if (!meaningful(current) && meaningful(saved)) {
        localStorage.setItem(key, saved);
        restored = true;
      }
    });
    if (restored) localStorage.setItem('g2_autosave_last_restore', new Date().toISOString());
  }
  restoreMissingData();
  const originalSetItem = localStorage.setItem.bind(localStorage);
  const originalRemoveItem = localStorage.removeItem.bind(localStorage);
  let backingUp = false;
  localStorage.setItem = function(key, value){
    originalSetItem(key, value);
    if (!backingUp && DATA_KEYS.includes(key)) {
      backingUp = true;
      setTimeout(() => { writeBackup(); backingUp = false; }, 0);
    }
  };
  localStorage.removeItem = function(key){
    originalRemoveItem(key);
    if (!backingUp && DATA_KEYS.includes(key)) {
      backingUp = true;
      setTimeout(() => { writeBackup(); backingUp = false; }, 0);
    }
  };
  window.addEventListener('beforeunload', writeBackup);
  setInterval(writeBackup, 30000);
  setTimeout(writeBackup, 1200);
})();

(function(){
  if(window.__g2MountWatchdog) return;
  window.__g2MountWatchdog=true;
  function isConnected(){
    return localStorage.getItem('g2_session')==='true';
  }
  function isDashboard(){
    const hash=(location.hash||'').replace(/^#/,'') || sessionStorage.getItem('g2_route') || '/dashboard';
    return hash==='/dashboard' || hash==='/';
  }
  function hasRealDashboard(){
    const root=document.getElementById('root');
    if(!root) return false;
    const text=root.innerText || '';
    return /Effectif|Dernieres consignes|Dernières consignes|Tirs a refaire|Tirs à refaire|Habilitations expirees|Habilitations expirées|Planning previsionnel|Planning prévisionnel|Planning hebdomadaire/.test(text);
  }
  function repairMount(){
    if(!isConnected() || !isDashboard() || hasRealDashboard()) return;
    if(typeof window.__g2RenderApp==='function'){
      window.__g2RenderApp();
    }
  }
  window.addEventListener('hashchange',function(){ setTimeout(repairMount,80); });
  window.addEventListener('storage',function(){ setTimeout(repairMount,80); });
  window.addEventListener('g2-react-ready',function(){ setTimeout(repairMount,40); });
  setTimeout(repairMount,250);
  setTimeout(repairMount,1000);
  setTimeout(repairMount,2000);
})();

