(function(){
  const STYLE_ID = 'g2-layout-left-menu-fix';
  function ensureLayoutFix(){
    if (document.getElementById(STYLE_ID)) return;
    const style = document.createElement('style');
    style.id = STYLE_ID;
    style.textContent = '@media (min-width:768px){body:not(.g2-login-screen) #root>div.flex.min-h-screen{display:flex!important;flex-direction:row!important;align-items:stretch!important}body:not(.g2-login-screen) #root aside{left:0!important;right:auto!important;order:0!important}body:not(.g2-login-screen) #root>div.flex.min-h-screen>div.flex.flex-1{order:1!important;min-width:0!important}body:not(.g2-login-screen) #root .md\:pl-64{padding-left:16rem!important}}@media (max-width:767px){body:not(.g2-login-screen) #root aside{left:0!important;right:auto!important}}';
    document.head.appendChild(style);
  }
  ensureLayoutFix();
})();

(function(){
  const id='g2-hide-empty-helper-text';
  if(document.getElementById(id)) return;
  const style=document.createElement('style');
  style.id=id;
  style.textContent='p.text-muted-foreground:empty,p.text-sm.text-muted-foreground:empty{display:none!important}';
  document.head.appendChild(style);
})();

(function(){
  const CARD_ID='g2-weekly-presence-card';
  const DAYS=['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];
  const PRESENT=new Set(['TVA','TVB','PERM','STAND','ACCUEIL','STAGE','SDF']);
  function isWeekly(){return location.pathname.replace(/\/+$/,'').endsWith('/planning-hebdomadaire');}
  function mondayISO(d){const dt=new Date(d);const day=(dt.getDay()+6)%7;dt.setDate(dt.getDate()-day);return dt.getFullYear()+'-'+String(dt.getMonth()+1).padStart(2,'0')+'-'+String(dt.getDate()).padStart(2,'0');}
  function todayName(){const d=new Date();return DAYS[(d.getDay()+6)%7];}
  function stats(){
    const agents=(typeof _cache!=='undefined'&&_cache.agents)||[];
    const weekly=(typeof _cache!=='undefined'&&_cache.weekly)||{};
    const monday=mondayISO(new Date());
    const day=todayName();
    const list=agents.filter(a=>a.actif!==false&&!String(a.id||'').startsWith('res-'));
    let present=0,absent=0,missing=0;
    list.forEach(a=>{
      const code=String(weekly[monday+'-'+a.id+'-'+day]||'').trim().toUpperCase();
      if(!code)missing++;else if(PRESENT.has(code))present++;else absent++;
    });
    const total=list.length;
    const rate=total?Math.round((present/total)*100):0;
    return {rate,present,absent,missing,total,day,date:new Date().toLocaleDateString('fr-FR')};
  }
  function render(card){
    const s=stats();
    card.innerHTML='<div style="display:flex;align-items:center;gap:14px;flex-wrap:wrap"><div style="width:64px;height:64px;border-radius:9999px;background:conic-gradient(#22c55e '+(s.rate*3.6)+'deg,#e5e7eb 0deg);display:flex;align-items:center;justify-content:center;font-weight:900;color:#166534;font-size:15px;flex-shrink:0">'+s.rate+'%</div><div><h2 style="font-size:15px;font-weight:800;color:#1A1A2E;margin:0">Taux de présence du jour</h2><p style="font-size:12px;color:#64748b;margin:2px 0 0">'+s.day+' '+s.date+' — calculé depuis le planning hebdomadaire</p></div></div><div style="display:flex;gap:14px;flex-wrap:wrap;margin-top:10px;font-size:12px;color:#334155"><span><b style="color:#166534">'+s.present+'</b> présents</span><span><b style="color:#b91c1c">'+s.absent+'</b> absents</span><span><b>'+s.total+'</b> effectifs</span><span><b style="color:#a16207">'+s.missing+'</b> non renseignés</span></div>';
  }
  function ensure(){
    if(!isWeekly()){const c=document.getElementById(CARD_ID);if(c)c.remove();return;}
    const h1=[...document.querySelectorAll('h1')].find(el=>/planning hebdomadaire/i.test(el.textContent||''));
    if(!h1)return;
    let card=document.getElementById(CARD_ID);
    const signature=JSON.stringify(stats());
    if(card){if(card.dataset.sig!==signature){card.dataset.sig=signature;render(card);}return;}
    card=document.createElement('section');
    card.id=CARD_ID;
    card.style.cssText='background:#fff;border:1px solid #e2e8f0;border-radius:16px;padding:16px 18px;box-shadow:0 8px 22px rgba(15,23,42,.06);margin:14px 0';
    card.dataset.sig=signature;
    render(card);
    const wrapper=h1.closest('div')||h1;
    wrapper.insertAdjacentElement('afterend',card);
  }
  setTimeout(ensure,400);
  window.addEventListener('popstate',()=>setTimeout(ensure,150));
  setInterval(ensure,2000);
})();

(function(){
  const BANNER_ID='g2-save-global-banner';
  function isLogin(){return localStorage.getItem('g2_session')!=='true';}
  function exportBackup(btn){
    try{
      const data={agents:(_cache&&_cache.agents)||[],leaves:(_cache&&_cache.leaves)||[],tirs:(_cache&&_cache.tirs)||[],habilitations:(_cache&&_cache.habilitations)||[],consignes:(_cache&&_cache.consignes)||[],weekly:(_cache&&_cache.weekly)||{},codes:(_cache&&_cache.codes)||[],exportedAt:new Date().toISOString()};
      const blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});
      const url=URL.createObjectURL(blob);
      const a=document.createElement('a');
      a.href=url;a.download='g2-connect-sauvegarde-'+new Date().toISOString().slice(0,10)+'.json';
      document.body.appendChild(a);a.click();a.remove();
      URL.revokeObjectURL(url);
      const old=btn.textContent;btn.textContent='ENREGISTRÉ ✓';setTimeout(()=>{btn.textContent=old;},1500);
    }catch(e){alert('Erreur lors de la sauvegarde');}
  }
  function makeBanner(){
    const banner=document.createElement('div');
    banner.id=BANNER_ID;
    banner.style.cssText='width:100%;box-sizing:border-box;margin-bottom:18px';
    const btn=document.createElement('button');
    btn.type='button';
    btn.textContent='SAUVEGARDER';
    btn.style.cssText='width:100%;box-sizing:border-box;display:block;text-align:center;background:linear-gradient(135deg,#001a8d,#ff6b00);color:#fff;font-weight:900;letter-spacing:.06em;border:none;border-radius:12px;padding:13px 16px;font-size:13px;cursor:pointer;box-shadow:0 6px 18px rgba(15,23,42,.14)';
    btn.onclick=()=>exportBackup(btn);
    banner.appendChild(btn);
    return banner;
  }
  function build(){
    if(isLogin()){const b=document.getElementById(BANNER_ID);if(b)b.remove();return;}
    const h1=[...document.querySelectorAll('h1')].find(el=>!/G2\s*CONNECT/i.test(el.textContent||''));
    if(!h1)return;
    const page=h1.closest('.space-y-6')||h1.closest('div')||h1;
    let banner=document.getElementById(BANNER_ID);
    if(banner){
      if(banner.nextElementSibling!==page){
        banner.remove();
        page.parentElement.insertBefore(banner,page);
      }
      return;
    }
    banner=makeBanner();
    page.parentElement.insertBefore(banner,page);
  }
  setTimeout(build,400);
  window.addEventListener('popstate',()=>setTimeout(build,150));
  setInterval(build,2000);
})();
